import os
import json
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
from urllib.parse import urlparse

app = Flask(__name__)
s3_client = boto3.client('s3')
ALLOWED_DOMAINS = ['example.com', 'anotherdomain.com']  # Add allowed domains here
BUCKET_NAME = 'your-s3-bucket-name'

def is_allowed_url(url):
    parsed_url = urlparse(url)
    return parsed_url.netloc in ALLOWED_DOMAINS

def is_internal_ip(ip):
    return ip.startswith(('10.', '172.', '192.168.'))

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')

    if not url or not is_allowed_url(url):
        return jsonify({'error': 'Invalid URL'}), 400

    # Set up headless Chrome options
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')

    # Start headless Chrome
    service = Service(ChromeDriverManager().install())
    driver = webdriver.Chrome(service=service, options=chrome_options)

    try:
        driver.get(url)
        screenshot_path = '/tmp/screenshot.png'
        driver.save_screenshot(screenshot_path)

        # Upload to S3
        s3_client.upload_file(screenshot_path, BUCKET_NAME, f'screenshots/{os.path.basename(url)}.png')

        return jsonify({'message': 'Screenshot saved', 'url': f'https://{BUCKET_NAME}.s3.amazonaws.com/screenshots/{os.path.basename(url)}.png'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        driver.quit()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))